function parseObject(value) {
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value)
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : undefined
    } catch {
      const trimmed = value.trim()
      if (!trimmed.includes('=')) return undefined

      const source = trimmed.startsWith('?') ? trimmed.slice(1) : trimmed
      const result = {}
      for (const pair of source.split('&')) {
        if (!pair) continue
        const separatorIndex = pair.indexOf('=')
        const rawKey = separatorIndex >= 0 ? pair.slice(0, separatorIndex) : pair
        const rawValue = separatorIndex >= 0 ? pair.slice(separatorIndex + 1) : ''
        const key = decodeURIComponent(rawKey.replace(/\+/g, ' '))
        const paramValue = decodeURIComponent(rawValue.replace(/\+/g, ' '))
        if (!key) continue

        if (result[key] === undefined) {
          result[key] = paramValue
        } else if (Array.isArray(result[key])) {
          result[key].push(paramValue)
        } else {
          result[key] = [result[key], paramValue]
        }
      }

      return Object.keys(result).length > 0 ? result : undefined
    }
  }
  return value && typeof value === 'object' && !Array.isArray(value) ? value : undefined
}

function readInput() {
  const raw = parseObject($json) ?? {}
  const directKeys = Object.keys(raw).filter((key) => !['json', 'body', 'query', 'data', 'input', 'workflowInputs', 'parameters', 'args'].includes(key))
  if (directKeys.length > 0) return raw

  for (const key of ['json', 'body', 'query', 'data', 'input', 'workflowInputs', 'parameters', 'args']) {
    const nested = parseObject(raw[key])
    if (nested && Object.keys(nested).length > 0) return nested
  }

  return raw
}

function present(value) {
  return value !== undefined && value !== null && value !== '' ? value : undefined
}

function numberOrUndefined(value) {
  const normalized = present(value)
  if (normalized === undefined) return undefined
  const parsed = Number(normalized)
  return Number.isInteger(parsed) ? parsed : undefined
}
const input = readInput()
const apiBaseUrl = 'http://host.docker.internal:3000/api/v1'
const from = present(input.from) ?? present(input.date)
const to = present(input.to) ?? present(input.from) ?? present(input.date)
const roomTypeCandidate = input.roomTypeId ?? input.roomType
const roomTypeId = numberOrUndefined(roomTypeCandidate)
return [{ json: { ...input, from, to, periodFrom: from, periodTo: to, roomType: present(input.roomType), roomTypeId, facilityId: numberOrUndefined(input.facilityId), dataStatus: numberOrUndefined(input.dataStatus) ?? 1, apiBaseUrl, internalToken: 'dev-internal-token', limit: numberOrUndefined(input.limit) ?? 50 } }]

function normalizeText(value) {
  return String(value ?? '').trim().toLowerCase()
}

function matchesRoomType(room, roomType) {
  const expected = normalizeText(roomType)
  if (!expected) return true
  return normalizeText(room.roomTypeName).includes(expected) || normalizeText(room.roomClassName).includes(expected)
}

function extractRows(result) {
  return Array.isArray(result)
    ? result
    : Array.isArray(result.availableRooms)
      ? result.availableRooms
      : Array.isArray(result.rooms)
        ? result.rooms
        : Array.isArray(result.data)
          ? result.data
          : Array.isArray(result.items)
            ? result.items
            : []
}

const input = $('Prepare Input').first().json
const rows = extractRows($json)
const availableRooms = rows.filter((room) => matchesRoomType(room, input.roomType))
return [{ json: { availableRooms, sources: [{ type: 'api', name: 'GET /rooms?periodFrom&periodTo' }] } }]
